-- Query: Query7
SELECT DISTINCTROW Sessions.SessionNumber AS SessionNumber, Format([Sessions].[DateTime],'mm/dd/yy') AS [Date], First(SessionItems.Description) AS SessionType, [Users].[FirstName]+' '+[Users].[LastName] AS SessionBy, [Photographers].[FirstName]+' '+[Photographers].[LastName] AS Photographer, Format([Sessions].[TotalDue],'Currency') AS Due, First(IIf([Sessions].[YBO]=True,IIf([SessionStatus].[Partial]=True,[SessionStatusLegend].[Description] & '-YBO- ' & [Sessions].[YBO_Date] & '-Part',[SessionStatusLegend].[Description] & '-YBO- ' & [Sessions].[YBO_Date]),IIf([SessionStatus].[Partial]=True,[SessionStatusLegend].[Description] & '-Part',[SessionStatusLegend].[Description]))) AS Status, Sessions.TotalDue, Sessions.SessionID, Studios.Name AS SessionLocation, Sessions.Roll, (SELECT Sum(DepositPayments.Amount) AS SumOfAmount From DepositPayments WHERE (((DepositPayments.SessionID)=Sessions.SessionID));) AS TotDeposits
FROM ((((Users INNER JOIN ((Photographers INNER JOIN Sessions ON Photographers.PhotographerID = Sessions.PhotographerID) LEFT JOIN (SessionItems RIGHT JOIN SessionDetail ON SessionItems.SessionItemID = SessionDetail.SessionItemID) ON Sessions.SessionID = SessionDetail.SessionID) ON Users.UserID = Sessions.UserID) INNER JOIN Studios ON Sessions.Studio = Studios.Studio) LEFT JOIN DepositPayments ON Sessions.SessionID = DepositPayments.SessionID) LEFT JOIN 000SessionStatus ON Sessions.SessionID = [000SessionStatus].SessionID) LEFT JOIN SessionStatusLegend ON [000SessionStatus].SessionStatusLegendID = SessionStatusLegend.SessionStatusLegendID
WHERE (((Sessions.CustomerID)=280013))
GROUP BY Sessions.SessionNumber, [Users].[FirstName]+' '+[Users].[LastName], [Photographers].[FirstName]+' '+[Photographers].[LastName], Sessions.TotalDue, Sessions.SessionID, Studios.Name, Sessions.Roll, Sessions.DateTime
ORDER BY Sessions.SessionNumber;

